namespace BlazorApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 4;
    private static readonly string[] SampleMessages =
    [
        "Your report is ready to download",
        "New comment on your pull request",
        "Deployment to production succeeded",
        "Disk usage exceeded 90%",
        "Weekly digest is available",
        "Your password expires in 3 days",
    ];

    /// <summary>
    /// Returns the initial set of notifications (used during SSR).
    /// </summary>
    public Task<List<Notification>> GetNotificationsAsync()
    {
        var initial = new List<Notification>
        {
            new(1, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-30)),
            new(2, "You have a new follower", DateTime.UtcNow.AddMinutes(-10)),
            new(3, "System maintenance scheduled for tonight", DateTime.UtcNow.AddMinutes(-2)),
        };
        return Task.FromResult(initial);
    }

    /// <summary>
    /// Simulates checking for new notifications. Returns 0-1 new items per call.
    /// </summary>
    public Task<List<Notification>> CheckForNewAsync()
    {
        var result = new List<Notification>();

        // ~40 % chance of a new notification each poll
        if (Random.Shared.Next(5) < 2)
        {
            var msg = SampleMessages[Random.Shared.Next(SampleMessages.Length)];
            result.Add(new Notification(_nextId++, msg, DateTime.UtcNow));
        }

        return Task.FromResult(result);
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject NotificationService NotificationSvc
@inject PersistentComponentState PersistentState

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group mt-3">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private PersistingComponentStateSubscription _persistSub;

    protected override async Task OnInitializedAsync()
    {
        // Register a callback so the SSR pass persists state into the HTML.
        _persistSub = PersistentState.RegisterOnPersisting(PersistNotifications);

        // Try to restore state that was embedded during SSR.
        // If found, we skip the service call entirely (interactive reconnect).
        if (!PersistentState.TryTakeFromJson<List<Notification>>(
                nameof(_notifications), out var restored))
        {
            // First render (SSR): load from the service.
            restored = await NotificationSvc.GetNotificationsAsync();
        }

        _notifications = restored ?? new();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // OnAfterRender only fires on the interactive runtime — never during
        // static SSR — so this is the safe place to kick off the polling loop.
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }

        await base.OnAfterRenderAsync(firstRender);
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);
                var fresh = await NotificationSvc.CheckForNewAsync();
                if (fresh.Count > 0)
                {
                    _notifications.AddRange(fresh);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                // Expected on dispose — exit cleanly.
                break;
            }
        }
    }

    private Task PersistNotifications()
    {
        PersistentState.PersistAsJson(nameof(_notifications), _notifications);
        return Task.CompletedTask;
    }

    public async ValueTask DisposeAsync()
    {
        _persistSub.Dispose();

        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

